const input = $input.first().json;
const body = input.body || input;
const topic_id = body.topic_id;

if (!topic_id) {
  throw new Error('topic_id is required');
}

return [{ json: { topic_id } }];

const scenes = $('Read Scenes').first().json;
const topic = $('Read Topic').first().json[0];
const project = $('Read Project').first().json[0];

const niche = project.niche || 'general';
const style_dna = project.style_dna || '';
const topic_title = topic.seo_title || topic.original_title || 'Untitled';
const topic_id = topic.id;
const project_id = topic.project_id;

// Batch scenes into groups of 30
const BATCH_SIZE = 30;
const batches = [];

for (let i = 0; i < scenes.length; i += BATCH_SIZE) {
  const batchScenes = scenes.slice(i, i + BATCH_SIZE);
  const scene_numbers = batchScenes.map(s => s.scene_number);
  const scene_ids = batchScenes.map(s => s.id);

  const scenesForPrompt = batchScenes.map(s => ({
    scene_number: s.scene_number,
    narration: (s.narration_text || '').substring(0, 300),
    image_prompt: (s.image_prompt || '').substring(0, 200),
    composition_prefix: s.composition_prefix || null,
    b_roll_insert: s.b_roll_insert || null
  }));

  const prompt = `You are a video production visual classifier. For each scene, determine if the visual should be:
1. "fal_ai" — photorealistic AI image (people, environments, products, mood imagery)
2. "remotion" — data graphic (numbers, comparisons, charts, timelines, lists, quotes, tables)

RULES:
- Specific numbers/prices/dates that must display accurately → "remotion"
- Narration explains data while showing mood image → "fal_ai" (data is spoken not shown)
- When in doubt → "fal_ai"
- For remotion scenes, select template and generate data_payload

Templates: stat_callout, comparison_layout, bar_chart, timeline_graphic, quote_card, list_breakdown, chapter_title, data_table, before_after, percentage_ring, map_visual, metric_highlight

VIDEO NICHE: ${niche}
VIDEO TOPIC: ${topic_title}
STYLE DNA: ${style_dna}

SCENES:
${JSON.stringify(scenesForPrompt, null, 2)}

OUTPUT: JSON array, one object per scene:
[{"scene_number":1,"render_method":"fal_ai","reasoning":"...","remotion_template":null,"data_payload":null},...]

For remotion scenes, data_payload must be a valid JSON object with the data needed for the template. Example for stat_callout: {"value":"$695","label":"Annual Fee","subtitle":"Amex Platinum"}

RESPOND ONLY WITH THE JSON ARRAY.`;

  batches.push({
    json: {
      batch_index: Math.floor(i / BATCH_SIZE),
      prompt,
      scene_numbers,
      scene_ids,
      topic_id,
      project_id,
      total_batches: Math.ceil(scenes.length / BATCH_SIZE)
    }
  });
}

return batches;

const response = $input.first().json;
const batchData = $('Loop Batches').first().json;
const scene_numbers = batchData.scene_numbers;
const scene_ids = batchData.scene_ids;
const topic_id = batchData.topic_id;
const supabaseUrl = $env.SUPABASE_URL;
const anonKey = $env.SUPABASE_ANON_KEY;
const serviceKey = $env.SUPABASE_SERVICE_ROLE_KEY;

let classifications = [];

try {
  // Extract text content from Anthropic response
  let text = '';
  if (response.content && Array.isArray(response.content)) {
    text = response.content.map(c => c.text || '').join('');
  } else if (typeof response === 'string') {
    text = response;
  } else {
    text = JSON.stringify(response);
  }

  // Strip markdown code fences if present
  text = text.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();

  classifications = JSON.parse(text);
} catch (parseErr) {
  // Default all scenes in this batch to fal_ai on parse failure
  classifications = scene_numbers.map((num, idx) => ({
    scene_number: num,
    render_method: 'fal_ai',
    reasoning: 'Classification parse failed, defaulting to fal_ai',
    remotion_template: null,
    data_payload: null
  }));
}

// PATCH each scene
const results = [];
for (let i = 0; i < scene_ids.length; i++) {
  const sceneId = scene_ids[i];
  const sceneNum = scene_numbers[i];
  const cls = classifications.find(c => c.scene_number === sceneNum) || {
    render_method: 'fal_ai',
    reasoning: 'No classification returned, defaulting to fal_ai',
    remotion_template: null,
    data_payload: null
  };

  const patchBody = {
    render_method: cls.render_method || 'fal_ai',
    classification_reasoning: cls.reasoning || '',
    classification_status: 'classified'
  };

  if (cls.render_method === 'remotion' && cls.remotion_template) {
    patchBody.remotion_template = cls.remotion_template;
    patchBody.data_payload = cls.data_payload ? (typeof cls.data_payload === 'string' ? cls.data_payload : JSON.stringify(cls.data_payload)) : null;
  }

  try {
    const resp = await fetch(
      `${supabaseUrl}/rest/v1/scenes?id=eq.${sceneId}`,
      {
        method: 'PATCH',
        headers: {
          'apikey': anonKey,
          'Authorization': `Bearer ${serviceKey}`,
          'Content-Type': 'application/json',
          'Prefer': 'return=minimal'
        },
        body: JSON.stringify(patchBody)
      }
    );
    results.push({ scene_number: sceneNum, status: 'updated', render_method: patchBody.render_method });
  } catch (fetchErr) {
    results.push({ scene_number: sceneNum, status: 'fetch_error', error: fetchErr.message });
  }
}

return [{ json: {
  batch_index: batchData.batch_index,
  topic_id,
  scenes_updated: results.length,
  results
} }];
